/**
 * Tests for the stale guidance mirror prune in session-start-launcher.mjs (#839)
 * and the pre-#939 moflo-bootstrap.md cleanup (#939).
 *
 * The launcher's section 3b restores missing shipped guidance files into
 * `.claude/guidance/` and prunes top-level mirrors whose source no longer
 * exists in `node_modules/moflo/.claude/guidance/shipped/`. The prune is
 * gated on the session-start AUTO-GENERATED marker so user-authored files
 * are never deleted.
 *
 * Section 3c-939 separately removes pre-#939 `moflo-bootstrap.md` (a renamed
 * duplicate of `moflo-subagents.md` written by older `flo init` / `flo-setup`).
 *
 * The launcher logic is plain ESM that imports moflo-paths; re-implementing
 * just the relevant steps here keeps the test isolated from the rest of the
 * launcher's startup work (db migrations, daemon recycling, etc.).
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { existsSync, readFileSync, writeFileSync, mkdirSync, rmSync, readdirSync, unlinkSync } from 'fs';
import { resolve } from 'path';

const SESSION_START_MARKER = '<!-- AUTO-GENERATED by moflo session-start.';

function makeTempRoot(): string {
  const root = resolve(__dirname, '../../.testoutput/.test-guidance-prune-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8));
  mkdirSync(resolve(root, '.claude/guidance'), { recursive: true });
  mkdirSync(resolve(root, 'node_modules/moflo/.claude/guidance/shipped'), { recursive: true });
  return root;
}

function cleanTempRoot(root: string) {
  try { rmSync(root, { recursive: true, force: true }); } catch { /* ok */ }
}

function sessionStartHeader(file: string) {
  return `<!-- AUTO-GENERATED by moflo session-start. Do not edit — changes will be overwritten. -->\n<!-- Source: node_modules/moflo/.claude/guidance/shipped/${file} -->\n\n`;
}

/** Mirrors the prune step in bin/session-start-launcher.mjs section 3b. */
function pruneStaleMirrors(projectRoot: string): number {
  const guidanceDir = resolve(projectRoot, '.claude/guidance');
  const shippedDir = resolve(projectRoot, 'node_modules/moflo/.claude/guidance/shipped');
  if (!existsSync(shippedDir) || !existsSync(guidanceDir)) return 0;
  const shippedSet = new Set(readdirSync(shippedDir).filter(f => f.endsWith('.md')));
  let pruned = 0;
  for (const file of readdirSync(guidanceDir)) {
    if (!file.endsWith('.md')) continue;
    if (shippedSet.has(file)) continue;
    const abs = resolve(guidanceDir, file);
    try {
      const head = readFileSync(abs, 'utf-8').slice(0, SESSION_START_MARKER.length);
      if (head !== SESSION_START_MARKER) continue;
      unlinkSync(abs);
      pruned++;
    } catch { /* non-fatal */ }
  }
  return pruned;
}

describe('guidance mirror prune (#839)', () => {
  let root: string;
  beforeEach(() => { root = makeTempRoot(); });
  afterEach(() => { cleanTempRoot(root); });

  it('removes top-level mirrors whose source no longer exists in shipped/', () => {
    // Stage shipped/ with the post-rename (spell) names only.
    const shipped = resolve(root, 'node_modules/moflo/.claude/guidance/shipped');
    writeFileSync(resolve(shipped, 'moflo-spell-connectors.md'), '# Spell Connectors\n');

    // Pre-populate the top-level mirror with stale workflow-* files
    // (the exact #839 reproduction) plus the matching spell file.
    const guidance = resolve(root, '.claude/guidance');
    writeFileSync(resolve(guidance, 'moflo-workflow-connectors.md'), sessionStartHeader('moflo-workflow-connectors.md') + 'old content');
    writeFileSync(resolve(guidance, 'moflo-workflow-engine-architecture.md'), sessionStartHeader('moflo-workflow-engine-architecture.md') + 'old content');
    writeFileSync(resolve(guidance, 'moflo-workflow-sandboxing.md'), sessionStartHeader('moflo-workflow-sandboxing.md') + 'old content');
    writeFileSync(resolve(guidance, 'moflo-spell-connectors.md'), sessionStartHeader('moflo-spell-connectors.md') + '# Spell Connectors\n');

    const pruned = pruneStaleMirrors(root);

    expect(pruned).toBe(3);
    expect(existsSync(resolve(guidance, 'moflo-workflow-connectors.md'))).toBe(false);
    expect(existsSync(resolve(guidance, 'moflo-workflow-engine-architecture.md'))).toBe(false);
    expect(existsSync(resolve(guidance, 'moflo-workflow-sandboxing.md'))).toBe(false);
    // Active mirror with a matching shipped source survives.
    expect(existsSync(resolve(guidance, 'moflo-spell-connectors.md'))).toBe(true);
  });

  it('leaves user-authored guidance files (no AUTO-GENERATED marker) untouched', () => {
    const shipped = resolve(root, 'node_modules/moflo/.claude/guidance/shipped');
    writeFileSync(resolve(shipped, 'moflo-subagents.md'), '# Subagents\n');

    const guidance = resolve(root, '.claude/guidance');
    // No marker — user-authored file with a name that matches no shipped source.
    writeFileSync(resolve(guidance, 'project-conventions.md'), '# My project conventions\n');
    // Still a stale mirror we should remove.
    writeFileSync(resolve(guidance, 'moflo-workflow-connectors.md'), sessionStartHeader('moflo-workflow-connectors.md') + 'stale');

    const pruned = pruneStaleMirrors(root);

    expect(pruned).toBe(1);
    expect(existsSync(resolve(guidance, 'project-conventions.md'))).toBe(true);
    expect(existsSync(resolve(guidance, 'moflo-workflow-connectors.md'))).toBe(false);
  });

  it('section 3b leaves moflo-bootstrap.md alone (separate 3c-939 step removes it)', () => {
    // Pre-#939 cleanup: section 3b is marker-gated on the launcher's own
    // session-start marker. moflo-bootstrap.md carries a different marker
    // (moflo init / flo-setup), so 3b skips it. The dedicated 3c-939 step
    // owns its removal — see the cleanupLegacyBootstrap test below.
    const shipped = resolve(root, 'node_modules/moflo/.claude/guidance/shipped');
    writeFileSync(resolve(shipped, 'moflo-subagents.md'), '# Subagents\n');

    const guidance = resolve(root, '.claude/guidance');
    const initHeader = '<!-- AUTO-GENERATED by moflo init. Do not edit — changes will be overwritten on next init. -->\n<!-- Source: moflo/.claude/guidance/shipped/moflo-subagents.md -->\n\n';
    writeFileSync(resolve(guidance, 'moflo-bootstrap.md'), initHeader + '# Bootstrap\n');

    const pruned = pruneStaleMirrors(root);

    expect(pruned).toBe(0);
    expect(existsSync(resolve(guidance, 'moflo-bootstrap.md'))).toBe(true);
  });

  it('no-op when shipped/ is missing (no node_modules/moflo install)', () => {
    rmSync(resolve(root, 'node_modules'), { recursive: true, force: true });
    const guidance = resolve(root, '.claude/guidance');
    writeFileSync(resolve(guidance, 'moflo-workflow-connectors.md'), sessionStartHeader('moflo-workflow-connectors.md') + 'stale');

    const pruned = pruneStaleMirrors(root);

    // Without a shipped directory we can't tell stale from current — bail.
    expect(pruned).toBe(0);
    expect(existsSync(resolve(guidance, 'moflo-workflow-connectors.md'))).toBe(true);
  });

  it('idempotent: a clean install runs the prune and removes nothing', () => {
    const shipped = resolve(root, 'node_modules/moflo/.claude/guidance/shipped');
    writeFileSync(resolve(shipped, 'moflo-spell-connectors.md'), '# Spell Connectors\n');
    writeFileSync(resolve(shipped, 'moflo-subagents.md'), '# Subagents\n');

    const guidance = resolve(root, '.claude/guidance');
    writeFileSync(resolve(guidance, 'moflo-spell-connectors.md'), sessionStartHeader('moflo-spell-connectors.md') + 'content');
    writeFileSync(resolve(guidance, 'moflo-subagents.md'), sessionStartHeader('moflo-subagents.md') + 'content');

    expect(pruneStaleMirrors(root)).toBe(0);
    expect(pruneStaleMirrors(root)).toBe(0);
    expect(existsSync(resolve(guidance, 'moflo-spell-connectors.md'))).toBe(true);
    expect(existsSync(resolve(guidance, 'moflo-subagents.md'))).toBe(true);
  });
});

/** Mirrors the 3c-939 cleanup in bin/session-start-launcher.mjs. */
function cleanupLegacyBootstrap(projectRoot: string): boolean {
  const legacy = resolve(projectRoot, '.claude/guidance/moflo-bootstrap.md');
  if (!existsSync(legacy)) return false;
  try {
    const head = readFileSync(legacy, 'utf-8').slice(0, 200);
    const ours = head.includes('AUTO-GENERATED by moflo init') || head.includes('AUTO-GENERATED by flo-setup');
    if (!ours) return false;
    unlinkSync(legacy);
    return true;
  } catch {
    return false;
  }
}

describe('legacy moflo-bootstrap.md cleanup (#939)', () => {
  let root: string;
  beforeEach(() => { root = makeTempRoot(); });
  afterEach(() => { cleanTempRoot(root); });

  it('removes moflo-bootstrap.md written by pre-#939 `moflo init`', () => {
    const guidance = resolve(root, '.claude/guidance');
    const initHeader = '<!-- AUTO-GENERATED by moflo init. Do not edit — changes will be overwritten on next init. -->\n<!-- Source: moflo/.claude/guidance/shipped/moflo-subagents.md -->\n\n';
    writeFileSync(resolve(guidance, 'moflo-bootstrap.md'), initHeader + '# Bootstrap\n');

    expect(cleanupLegacyBootstrap(root)).toBe(true);
    expect(existsSync(resolve(guidance, 'moflo-bootstrap.md'))).toBe(false);
  });

  it('removes moflo-bootstrap.md written by pre-#939 `flo-setup`', () => {
    const guidance = resolve(root, '.claude/guidance');
    const setupHeader = '<!-- AUTO-GENERATED by flo-setup. Do not edit — changes will be overwritten. -->\n\n';
    writeFileSync(resolve(guidance, 'moflo-bootstrap.md'), setupHeader + '# Bootstrap\n');

    expect(cleanupLegacyBootstrap(root)).toBe(true);
    expect(existsSync(resolve(guidance, 'moflo-bootstrap.md'))).toBe(false);
  });

  it('preserves a homonymous user-authored moflo-bootstrap.md (no AUTO-GENERATED marker)', () => {
    const guidance = resolve(root, '.claude/guidance');
    writeFileSync(resolve(guidance, 'moflo-bootstrap.md'), '# My custom bootstrap notes\n');

    expect(cleanupLegacyBootstrap(root)).toBe(false);
    expect(existsSync(resolve(guidance, 'moflo-bootstrap.md'))).toBe(true);
  });

  it('idempotent: no-op when file is already gone', () => {
    expect(cleanupLegacyBootstrap(root)).toBe(false);
    expect(cleanupLegacyBootstrap(root)).toBe(false);
  });
});

describe('launcher source contains the prune step (drift guard)', () => {
  it('bin/session-start-launcher.mjs ships the prune logic', () => {
    const launcherSrc = readFileSync(resolve(__dirname, '../../bin/session-start-launcher.mjs'), 'utf-8');
    expect(launcherSrc).toContain('pruned stale guidance mirror files');
    expect(launcherSrc).toContain(SESSION_START_MARKER);
  });

  it('bin/session-start-launcher.mjs ships the #939 legacy bootstrap cleanup', () => {
    const launcherSrc = readFileSync(resolve(__dirname, '../../bin/session-start-launcher.mjs'), 'utf-8');
    expect(launcherSrc).toContain('3c-939');
    expect(launcherSrc).toContain('moflo-bootstrap.md');
    expect(launcherSrc).toContain('AUTO-GENERATED by moflo init');
    expect(launcherSrc).toContain('AUTO-GENERATED by flo-setup');
  });

  // Single-source-of-truth guard. If anyone edits the marker text on the
  // write site (sessionStartMirrorHeader) without updating the prune match
  // (SESSION_START_MIRROR_MARKER), the prune silently stops recognizing its
  // own files — exactly the regression class #839 paid for. Both must derive
  // from the same constant.
  it('write-site header and prune marker share a single constant', () => {
    const launcherSrc = readFileSync(resolve(__dirname, '../../bin/session-start-launcher.mjs'), 'utf-8');
    expect(launcherSrc).toContain('const SESSION_START_MIRROR_MARKER =');
    expect(launcherSrc).toContain('function sessionStartMirrorHeader(');
    // The literal marker text must appear exactly once — in the const
    // declaration. The helper and the prune both reference the constant
    // by name, so any other occurrence is drift waiting to bite.
    const occurrences = launcherSrc.split('<!-- AUTO-GENERATED by moflo session-start.').length - 1;
    expect(occurrences).toBe(1);
  });
});
